INSERT INTO `comments` VALUES (1,1,1,NULL,NULL,NULL,'双桂湖风景很好，环湖步道很舒适',5,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(2,2,NULL,1,NULL,NULL,'张鸭子味道很正，外酥里嫩',5,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(3,3,NULL,NULL,1,NULL,'年画很有特色，值得参观',5,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(4,4,NULL,NULL,NULL,1,'度假酒店服务好，早餐丰富',4,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(5,5,3,NULL,NULL,NULL,'竹海空气清新，拍照出片',5,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(6,6,NULL,6,NULL,NULL,'观景咖啡店视野好，甜点不错',4,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(7,7,NULL,NULL,NULL,3,'民宿庭院安静，适合休闲',5,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(8,8,2,NULL,NULL,NULL,'古镇人不多，逛起来舒服',4,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(9,9,NULL,4,NULL,NULL,'竹荪汤鲜美，推荐',5,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(10,10,NULL,NULL,NULL,9,'温泉酒店池子多，放松身心',4,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(11,1,1,NULL,NULL,NULL,'梁平景点体验评价 1',1,1,'2025-11-30 20:29:15','2025-11-30 20:29:15'),(12,2,2,NULL,NULL,NULL,'梁平景点体验评价 2',2,1,'2025-11-29 20:29:15','2025-11-30 20:29:15'),(13,3,3,NULL,NULL,NULL,'梁平景点体验评价 3',3,1,'2025-11-28 20:29:15','2025-11-30 20:29:15'),(14,4,4,NULL,NULL,NULL,'梁平景点体验评价 4',4,1,'2025-11-27 20:29:15','2025-11-30 20:29:15'),(15,5,5,NULL,NULL,NULL,'梁平景点体验评价 5',5,1,'2025-11-26 20:29:15','2025-11-30 20:29:15'),(16,6,6,NULL,NULL,NULL,'梁平景点体验评价 6',1,1,'2025-11-25 20:29:15','2025-11-30 20:29:15'),(17,7,7,NULL,NULL,NULL,'梁平景点体验评价 7',2,1,'2025-11-24 20:29:15','2025-11-30 20:29:15'),(18,8,8,NULL,NULL,NULL,'梁平景点体验评价 8',3,1,'2025-11-23 20:29:15','2025-11-30 20:29:15'),(19,9,1,NULL,NULL,NULL,'梁平景点体验评价 9',4,1,'2025-11-22 20:29:15','2025-11-30 20:29:15'),(20,10,2,NULL,NULL,NULL,'梁平景点体验评价 10',5,1,'2025-11-21 20:29:15','2025-11-30 20:29:15'),(21,1,3,NULL,NULL,NULL,'梁平景点体验评价 11',1,1,'2025-11-20 20:29:15','2025-11-30 20:29:15'),(22,2,4,NULL,NULL,NULL,'梁平景点体验评价 12',2,1,'2025-11-19 20:29:15','2025-11-30 20:29:15'),(23,3,5,NULL,NULL,NULL,'梁平景点体验评价 13',3,1,'2025-11-18 20:29:15','2025-11-30 20:29:15'),(2