  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '菜品名称',
  `description` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '菜品描述',
  `price` decimal(10,2) DEFAULT NULL COMMENT '价格',
  `image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '菜品图片',
  `is_recommended` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否推荐菜：1-是，0-否',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '展示顺序（同一店铺内）',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
