DROP TABLE IF EXISTS `restaurants`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `restaurants` (
  `id` int NOT NULL AUTO_INCREMENT,
  `category_id` int DEFAULT NULL COMMENT '餐厅分类ID，对应 restaurant_categories.id',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '餐厅/美食名称',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '描述',
  `location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '地理位置',
  `latitude` decimal(10,8) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(11,8) DEFAULT NULL COMMENT '经度',
  `cover_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '封面图片',
  `images` text COLLATE utf8mb4_unicode_ci COMMENT '图片JSON数组',
  `open_hours` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '营业时间',
  `price_range` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '价格区间(如:￥50-100)',
  `specialty` bigint DEFAULT NULL COMMENT '招牌菜菜品ID',
  `contact_phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联系电话',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `rating` decimal(2,1) DEFAULT NULL COMMENT '推荐指数(0-5)',
  PRIMARY KEY (`id`),
  KEY `idx_restaurants_location` (`location`),
  KEY `idx_restaurants_category` (`category_id`),
  KEY `idx_restaurants_rating` (`rating`),
  KEY `idx_restaurants_specialty` (`specialty`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='美食店铺表';
/*!40101 SET character_set_client = @saved_cs_client */;

